<%_
const stat = (typeof getvar === 'function' ? getvar('stat_data') : ((typeof variables !== 'undefined' && variables.stat_data) ? variables.stat_data : {})) || {};
const period = _.get(stat, 'world_time.period', '沦陷期');
const allowedMap = {
  '沦陷期': ['普通感染者', '奔跑种', '食腐种', '夜视种'],
  '末日期初期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种'],
  '末日期中期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型'],
  '末日期末期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型'],
  '巢化期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型', '残巢种', '变异体'],
  '重建期': ['普通感染者', '奔跑种', '食腐种', '夜视种', '潜伏种', '甲壳种', '寻声种', '毒气种', '母巢', '融合型', '残巢种', '变异体']
};
const allTypes = allowedMap['重建期'];
const allowed = allowedMap[period] || allowedMap['沦陷期'];
const forbidden = allTypes.filter(x => !allowed.includes(x));
const compact = {
  user_profile: _.pick(_.get(stat, 'user_profile', {}), ['origin_identity', 'opening_location', 'current_location', 'current_goal', 'skills']),
  world_time: _.get(stat, 'world_time', {}),
  survival: _.get(stat, 'survival', {}),
  inventory: _.get(stat, 'inventory', {}),
  mainline: _.get(stat, 'mainline', {}),
  factions: _.get(stat, 'factions', {}),
  npcs: _.pickBy(_.get(stat, 'npcs', {}), v => v && v.status !== '未遇见'),
  quests: _.get(stat, 'quests', {}),
  local_events: _.get(stat, 'local_events', {}),
  monster_knowledge: _.get(stat, 'monster_knowledge', {})
};
_%>
<status_current_variables>
当前时期: <%- period %>
当前可正式出现怪物: <%- allowed.join('、') %>
禁止提前正式登场怪物: <%- forbidden.length ? forbidden.join('、') : '无' %>
规则: 禁止让未到时期的怪物实际遭遇或造成战斗；只能作为传闻、误判、记录或梦境。
当前变量快照:
<%- JSON.stringify(compact, null, 2) %>
</status_current_variables>

